/*    _   __   ___    _   ____    _    _        _____    ___     _____     | | / /  / _ \  | | |  _ \  | |  | |      |___  |  / _ \   |  ___|     | |/ /  | |_| | | | | |_| | |  \/  |         / /  | |_| |  | |__     |   /   |  _  | | | |  _ /  | |\/| |        / /   |  _  |  |  __|     | |\ \  | | | | | | | | \ \ | |  | |       / /__  | | | |  | |     |_| \_\ |_| |_| |_| |_| |_| |_|  |_|      |_____| |_| |_|  |_|      */#include<bits/stdc++.h>#pragma GCC optimize("O3")#pragma GCC optimize ("unroll-loops")#pragma GCC optimize("Ofast")#pragma GCC target("avx,avx2,fma")using namespace std;typedef long long ll ;#ifndef ONLINE_JUDGE#include "debug.cpp"#else#define kar(...)#endif#define pb push_back#define F first#define S second#define all(x) x.begin(),x.end()#define rall(x) x.rbegin(),x.rend()#define endl '\n' const ll N = 2e6+ 5 ,  MOD =1e9+7, mod=1e9+7, INF = 5e18 ; int spf[N] ,v[N] ;priority_queue <pair <int,int>> s ;int n , q , cnt, curr ; void sieve (){    for (int i= 2 ; i< N ; i++){        if (spf[i]) continue;        for (int j= i ; j<N ; j+=i) spf[j]= i ;    }}template<class T> struct Seg { // comb(ID,b) = b    const T ID = 0;    ll n; vector<T> seg;    T comb(T a, T b) { return  max(a,b); }    void build(ll _n) { n = _n; seg.assign(2*n,ID); }    void pull(ll p) { seg[p] = comb(seg[2*p],seg[2*p+1]); }    void upd(ll p, T val) { // set val at position p        seg[p += n] = val; for (p /= 2; p; p /= 2) pull(p); }    T query(ll l, ll r) {   // sum on llerval [l, r]        T ra = ID, rb = ID;        for (l += n, r += n+1; l < r; l /= 2, r /= 2) {            if (l&1) ra = comb(ra,seg[l++]);            if (r&1) rb = comb(seg[--r],rb);        }return comb(ra,rb);    }}; void solve(){    sieve(); cnt = 1 ;    cin >> n>> q ;    Seg <int> st ;    st.build (n);    for (int i= 0 ; i<n ;i++) {        cin>> v[i] ;        if (v[i]!=1 ) s.push({v[i],-i});    }    while (!s.empty()) {        pair <int,int> p = s.top(); s.pop();        curr = p.F / spf[p.F];        if ( curr == 1 ) st.upd(-p.S , cnt) ;        else s.push({ curr , p.S}) ; cnt++ ;    }     while (q--){        int l , r ;        cin >> l >> r ;        cout << st.query(--l,--r) << endl;    }}  int32_t main(){    #ifndef ONLINE_JUDGE    freopen("input.txt","r",stdin);freopen("output.txt","w",stdout);    #endif    ios::sync_with_stdio(false);cin.tie(NULL);srand(time(0)); ll test_case=1;//    cin >> test_case ;    while (test_case--)  solve() ;} // Failure gives you two choices: You stay down or You get up ;)